// solutions/ncnn/reference-scalar/conv2d/<def>_naive — scalar conv2d.
//
// Phase 1 smoke kernel. Implements ncnn::convolution_kernel as a straight
// 6-loop scalar accumulator. Assumes bottom_blob is already padded (the
// harness's armbench_entry_conv2d does the padding before this is called).
// Activation handled: type=0 (none) and type=1 (relu); others ignored.

#include "conv2d.h"

namespace ncnn {

int convolution_kernel(const Mat& bottom_blob, Mat& top_blob,
                       const Mat& weight_data, const Mat& bias_data,
                       int kernel_w, int kernel_h,
                       int stride_w, int stride_h,
                       int dilation_w, int dilation_h,
                       int activation_type, const Mat& activation_params,
                       const Option& /*opt*/)
{
    (void)activation_params;
    const int in_c  = bottom_blob.c;
    const int in_h  = bottom_blob.h;
    const int in_w  = bottom_blob.w;
    const int out_c = top_blob.c;
    const int out_h = top_blob.h;
    const int out_w = top_blob.w;

    const bool has_bias = !bias_data.empty();
    const float* W = (const float*)weight_data.data;
    const float* B = has_bias ? (const float*)bias_data.data : nullptr;

    for (int oc = 0; oc < out_c; ++oc) {
        float* outptr = top_blob.channel(oc);
        for (int oh = 0; oh < out_h; ++oh) {
            for (int ow = 0; ow < out_w; ++ow) {
                float sum = has_bias ? B[oc] : 0.0f;
                for (int ic = 0; ic < in_c; ++ic) {
                    const float* inptr = bottom_blob.channel(ic);
                    for (int khi = 0; khi < kernel_h; ++khi) {
                        for (int kwi = 0; kwi < kernel_w; ++kwi) {
                            int ih = oh * stride_h + khi * dilation_h;
                            int iw = ow * stride_w + kwi * dilation_w;
                            float px = inptr[ih * in_w + iw];
                            int widx = ((oc * in_c + ic) * kernel_h + khi) * kernel_w + kwi;
                            sum += px * W[widx];
                        }
                    }
                }
                if (activation_type == 1 && sum < 0.0f) sum = 0.0f;
                outptr[oh * out_w + ow] = sum;
            }
        }
    }
    return 0;
}

} // namespace ncnn
